// Parse email and determine ticket info
const email = $input.first().json.body;

// Extract key info
const fromEmail = email.from_email || email.from;
const subject = email.subject || 'No Subject';
const body = email.body_text || email.body_plain || email.body_html || '';
const attachments = email.attachments || [];

// Try to match to existing account
const matchEmail = fromEmail.toLowerCase().trim();

// Categorize based on subject/body keywords
let category = 'general';
let priority = 'medium';

const subjectLower = subject.toLowerCase();
const bodyLower = body.toLowerCase();

if (subjectLower.includes('claim') || bodyLower.includes('claim')) {
  category = 'claims';
  priority = 'high';
} else if (subjectLower.includes('cancel') || bodyLower.includes('cancel')) {
  category = 'cancellation';
  priority = 'high';
} else if (subjectLower.includes('bill') || bodyLower.includes('payment') || bodyLower.includes('invoice')) {
  category = 'billing';
} else if (subjectLower.includes('certificate') || subjectLower.includes('coi')) {
  category = 'certificate';
  priority = 'high';
} else if (subjectLower.includes('change') || subjectLower.includes('endorsement') || subjectLower.includes('add driver') || subjectLower.includes('add vehicle')) {
  category = 'endorsement';
}

// Check for urgent keywords
if (subjectLower.includes('urgent') || subjectLower.includes('asap') || subjectLower.includes('emergency')) {
  priority = 'urgent';
}

return {
  from_email: fromEmail,
  subject: subject,
  body_preview: body.substring(0, 500),
  category: category,
  priority: priority,
  has_attachments: attachments.length > 0,
  attachment_count: attachments.length,
  original_message_id: email.message_id
};
